"use client";

import { useState } from "react";

export function Counter() {
  const [count, setCount] = useState(0);
  return (
    <button type="button" onClick={() => setCount((c) => c + 1)}>
      Count: {count}
    </button>
  );
}

import { useEffect, useState } from "react";

export function WindowWidth() {
  const [w, setW] = useState(0);
  useEffect(() => {
    const onResize = () => setW(window.innerWidth);
    onResize();
    window.addEventListener("resize", onResize);
    return () => window.removeEventListener("resize", onResize);
  }, []);
  return <span>{w}px</span>;
}

import { createContext, useContext, useState } from 'react';

const ThemeCtx = createContext<'light' | 'dark'>('light');

export function App() {
  const [theme, setTheme] = useState<'light' | 'dark'>('light');
  return (
    <ThemeCtx.Provider value={theme}>
      <Toolbar setTheme={setTheme} />
    </ThemeCtx.Provider>
  );
}

function Toolbar({ setTheme }: { setTheme: (t: 'light' | 'dark') => void }) {
  const theme = useContext(ThemeCtx);
  return <button type="button" onClick={() => setTheme(theme === 'light' ? 'dark' : 'light')}>toggle</button>;
}

type S = { step: number };
type A = { type: 'next' } | { type: 'back' };

function reducer(s: S, a: A): S {
  switch (a.type) {
    case 'next': return { step: s.step + 1 };
    case 'back': return { step: Math.max(0, s.step - 1) };
  }
}

const [state, dispatch] = useReducer(reducer, { step: 0 });

